public function user_report101()
    {
        // Check if user is logged in
        if (!$this->session->userdata('logged_in')) {
            redirect('users/login'); // Or your login page
        }

        // Get username (which is the employee_id for table ev_done)
        $username = $this->session->userdata('username');
        
        // Get evaluation data from the model
        $data['evaluations'] = $this->user_model->get_my_evaluations($username);
        
        // Load the view with the new data
        // Using your setview function
        $this->load->view('template/new_header_and_sidebar');
        $this->load->view('templateo/user_report101', $data);
        $this->load->view('template/new_footer');
        
        // Or load directly if setview is not appropriate
        // $this->load->view('templateo/header');
        // $this->load->view('user_report101', $data);
        // $this->load->view('templateo/footer');
    }

    /**
     * Controller function to show the A4 print view for a single evaluation.
     * @param int $id The ID of the ev_done record
     */
  public function view_my_evaluation($id = NULL)
    {
        if (!$this->session->userdata('logged_in')) {
            redirect('users/login');
        }
        if ($id === NULL) {
            redirect('users/user_report101');
        }

        $username = $this->session->userdata('username');
        
        // 1. Get the evaluation record (from ev_done)
        $data['ev_done'] = $this->user_model->get_single_evaluation($id, $username);

        // 2. Get the employee's base details (from ev_emp)
        // This replaces the old placeholder and fetches real data
        $data['ev_emp22'] = $this->user_model->get_employee_details($username);
        
        if (!empty($data['ev_done'])) {
            // Now the A4 view will have both $ev_done and $ev_emp22
            
            $this->load->view('templateo/inv2', $data);
        } else {
            // Not found or doesn't belong to user
            $this->session->set_flashdata('error', 'Evaluation not found.');
            redirect('users/user_report101');
        }
    }

