    public function upload_attribution_file($project_id)
{
    $this->load->model('user_model');

    if (!empty($_FILES['attribution_file']['name'])) {
        $file_tmp = $_FILES['attribution_file']['tmp_name'];
        $file_ext = pathinfo($_FILES['attribution_file']['name'], PATHINFO_EXTENSION);

        if (strtolower($file_ext) !== 'csv') {
            $this->session->set_flashdata('error', 'يرجى رفع ملف بصيغة CSV فقط.');
            redirect('users/project_view/' . $project_id);
        }

        // Delete existing if checkbox is checked
        if (!empty($_POST['clear_existing']) && $_POST['clear_existing'] == '1') {
            $this->db->where('project_id', $project_id);
            $this->db->delete('attribution');
        }

        $handle = fopen($file_tmp, 'r');
        if (!$handle) {
            $this->session->set_flashdata('error', 'تعذر قراءة الملف.');
            redirect('users/project_view/' . $project_id);
        }

        $header = fgetcsv($handle); // skip header
        $rowCount = 0;

        while (($row = fgetcsv($handle)) !== FALSE) {
            $data = [
                'n1'         => $row[0],
                'n2'         => $row[1],
                'n3'         => $row[2],
                'project'    => $row[3],
                'project_id' => $project_id,
                'n5'         => $row[4],
                'n6'         => $row[5],
                'h1'         => $row[6],
                'h2'         => $row[7],
                'h3'         => $row[8],
                'h4'         => $row[9],
                'h5'         => $row[10],
                'h6'         => $row[11],
                'h7'         => $row[12],
                'h8'         => $row[13],
                'h9'         => $row[14],
                'h10'        => $row[15],
                'h11'        => $row[16],
                'status'     => $row[17],
                'status_emp' => $row[18],
                'emp_det'    => $row[19],
                'date_emp'   => $row[20],
                'status_com' => $row[21],
                'com_det'    => $row[22],
                'date_com'   => $row[23],
                'status_emp1'=> $row[24],
                'emp_det1'   => $row[25],
                'cic'        => $row[26],
                'mang_name'  => $row[27],
                'mang_id'    => $row[28],
            ];

            $this->user_model->insert_or_update_attribution($data);
            $rowCount++;
        }

        fclose($handle);
        $this->session->set_flashdata('success', "تم تحميل وتحديث $rowCount صفوف بنجاح.");
    } else {
        $this->session->set_flashdata('error', 'يرجى اختيار ملف للرفع.');
    }

    redirect('users/wallet/' . $project_id);
}

