public function upload_billfold_file15($project_id)
{

    

    // تعطيل حدود الوقت والذاكرة
    ini_set('max_execution_time', 0);
    ini_set('memory_limit', '-1');

    $this->load->model('user_model');

    if (!empty($_FILES['billfold_file']['name'])) {
        $file_tmp = $_FILES['billfold_file']['tmp_name'];
        $file_ext = pathinfo($_FILES['billfold_file']['name'], PATHINFO_EXTENSION);

        if (strtolower($file_ext) !== 'csv') {
            $this->session->set_flashdata('error', 'يرجى رفع ملف بصيغة CSV فقط.');
            redirect('users/project_view/' . $project_id);
        }

        // حذف البيانات القديمة إذا تم تحديد الخيار
        if (!empty($_POST['clear_existing']) && $_POST['clear_existing'] == '1') {
            $this->db->where('project_id', $project_id);
            $this->db->delete('billfold15');
        }

        $handle = fopen($file_tmp, 'r');
        if (!$handle) {
            $this->session->set_flashdata('error', 'تعذر قراءة الملف.');
            redirect('users/project_view/' . $project_id);
        }

        // تخطي الهيدر
        fgetcsv($handle);

        $rowCount = 0;

        while (($row = fgetcsv($handle)) !== FALSE) {
            if (empty(array_filter($row))) continue; // تجاهل الصفوف الفارغة

            $data = [
                'n1'           => $row[0],
                'n2'           => $row[1],
                'n3'           => $row[2],
                'n4'           => $row[3],
                'n5'           => $row[4],
                'project'      => $row[5],
                'project_id'   => $project_id,
   'n7'           => $row[7],
'n8'           => $row[8],
'n9'           => $row[9],
'n10'          => $row[10],
'n11'          => $row[11],
'h1'           => $row[12],
'h2'           => $row[13],
'h3'           => $row[14],
'h4'           => $row[15],
'h5'           => $row[16],
'h6'           => $row[17],
'status'       => $row[18],
'k1'           => $row[19],
'k2'           => $row[20],
'k3'           => $row[21],
'k4'           => $row[22],
'k5'           => $row[23],
'k6'           => $row[24],
'k7'           => $row[25],
'k8'           => $row[26],
'k9'           => $row[27],
'k10'          => $row[28],
'k11'          => $row[29],
'k12'          => $row[30],
'username'     => $row[31],
'emp_name'     => $row[32],
'sub_id'       => $row[33],
'sub_name'     => $row[34],
'total_amount' => $row[35],
'status2'      => $row[36],
'note101'      => $row[37],
'com_status'   => $row[38],
'com_details'  => $row[39],
'c1'  => $row[40],
'c2'  => $row[41],
'c3'  => $row[42],
'c4'  => $row[43],
'c5'  => $row[44],
'c6'  => $row[45],
'c7'  => $row[46],
'c9'  => $row[47],
'c10'  => $row[48],
'c11'  => $row[49],
'c12'  => $row[50],
'cic'  => $row[51],

            ];

            // استخدام REPLACE INTO ليتجاوز الحاجة للتحقق


             


            $this->user_model->replace_billfold15($data);

            $rowCount++;
        }

        fclose($handle);
        $this->session->set_flashdata('success', "تم تحميل وتحديث $rowCount صفوف بنجاح.");
    } else {
        $this->session->set_flashdata('error', 'يرجى اختيار ملف للرفع.');
    }

    redirect('users/upload_files_list/' . $project_id);
}

