 public function update_column_by_identity($project_id, $column_name)
{
    // خريطة الجداول حسب المشروع
    $project_tables = [
        1  => 'attribution',
        5  => 'attribution1',
        55 => 'attribution2',
        4  => 'attribution3',
        3  => 'attribution4',
        33 => 'attribution5',
        6  => 'attribution6',
        7  => 'attribution7',
        2  => 'attribution8',
        8  => 'attribution9',
        9  => 'attribution10',
        10 => 'attribution11',
        11 => 'attribution12',
        12 => 'attribution13',
        14 => 'attribution14',
        15 => 'attribution15'
    ];

    // تحقق من المشروع
    if (!isset($project_tables[$project_id])) {
        $this->session->set_flashdata('error', 'المشروع غير مدعوم.');
        redirect('users/project_view/' . $project_id);
    }

    $table = $project_tables[$project_id];

    // تحقق من العمود المسموح
    $allowed_columns = [
        'n1','n2','n3','n4','n5','h1','h2','h3','h4','h5','h6','h7',
        'status','status_emp','status_emp1','emp_det','emp_det1',
        'date_emp','date_com','category','status2','stabilizing','com_det'
    ];

    if (!in_array($column_name, $allowed_columns)) {
        $this->session->set_flashdata('error', 'العمود غير مسموح بتعديله.');
        redirect('users/project_view/' . $project_id);
    }

    // ضبط حدود الوقت والذاكرة للملفات الضخمة
    ini_set('max_execution_time', 0);  // وقت غير محدود
    ini_set('memory_limit', '-1');     // ذاكرة غير محدودة

    // التأكد من رفع ملف
    if (!empty($_FILES['billfold_file']['name'])) {
        $file_tmp = $_FILES['billfold_file']['tmp_name'];
        $file_ext = pathinfo($_FILES['billfold_file']['name'], PATHINFO_EXTENSION);

        if (strtolower($file_ext) !== 'csv') {
            $this->session->set_flashdata('error', 'يرجى رفع ملف بصيغة CSV فقط.');
            redirect('users/project_view/' . $project_id);
        }

        $handle = fopen($file_tmp, 'r');
        if (!$handle) {
            $this->session->set_flashdata('error', 'تعذر قراءة الملف.');
            redirect('users/project_view/' . $project_id);
        }

        // تخطي الهيدر
        fgetcsv($handle);

        $rowCount = 0;
        $batchSize = 1000; // عدد الصفوف لكل دفعة
        $batchData = [];

        while (($row = fgetcsv($handle)) !== FALSE) {
            if (empty(array_filter($row))) continue;

            $identity = $row[0];      // رقم الهوية
            $new_value = $row[1];     // القيمة الجديدة

            $batchData[] = [
                'identity'   => $identity,
                'new_value'  => $new_value
            ];

            // تنفيذ التحديث كل 1000 صف
            if (count($batchData) >= $batchSize) {
                $this->_process_batch_update($table, $column_name, $batchData);
                $rowCount += count($batchData);
                $batchData = []; // تصفير الدفعة
            }
        }

        // معالجة أي بيانات متبقية
        if (!empty($batchData)) {
            $this->_process_batch_update($table, $column_name, $batchData);
            $rowCount += count($batchData);
        }

        fclose($handle);

        $this->session->set_flashdata('success', "تم تعديل $rowCount صف بنجاح.");
    } else {
        $this->session->set_flashdata('error', 'يرجى اختيار ملف للرفع.');
    }

    redirect('users/upload_files_list/' . $project_id);
}

public function update_billfold_column_by_identity($project_id, $column_name)
{
    // خريطة مشاريع Billfold
    $billfold_tables = [
        1  => 'billfold',
        5  => 'billfold1',
        55 => 'billfold2',
        4  => 'billfold3',
        3  => 'billfold4',
        33 => 'billfold5',
        6  => 'billfold6',
        7  => 'billfold7',
        2  => 'billfold8',
        8  => 'billfold9',
        9  => 'billfold10',
        10 => 'billfold11',
        11 => 'billfold12',
        12 => 'billfold13',
        14 => 'billfold14',
        15 => 'billfold15'
    ];

    // تحقق من وجود المشروع في الخريطة
    if (!isset($billfold_tables[$project_id])) {
        $this->session->set_flashdata('error', 'المشروع غير مدعوم.');
        redirect('users/project_view/' . $project_id);
    }

    // تحديد الجدول الصحيح
    $table = $billfold_tables[$project_id];

    // تحقق من الأعمدة المسموح بتعديلها
    $allowed_columns = [
        'n1','n2','n3','n4','n5','n7','n8','n9','n10','n11',
        'h1','h2','h3','h4','h5','h6','status','k1','k2','k3','k4','k5','k6','k7','k8','k9','k10','k11','k12',
        'username','emp_name','sub_id','sub_name','total_amount','status2','note101','com_status','com_details'
    ];

    if (!in_array($column_name, $allowed_columns)) {
        $this->session->set_flashdata('error', 'العمود غير مسموح بتعديله.');
        redirect('users/project_view/' . $project_id);
    }

    // ضبط حدود الوقت والذاكرة للملفات الكبيرة
    ini_set('max_execution_time', 0);
    ini_set('memory_limit', '-1');

    // التأكد من وجود ملف مرفوع
    if (!empty($_FILES['billfold_file']['name'])) {
        $file_tmp = $_FILES['billfold_file']['tmp_name'];
        $file_ext = pathinfo($_FILES['billfold_file']['name'], PATHINFO_EXTENSION);

        if (strtolower($file_ext) !== 'csv') {
            $this->session->set_flashdata('error', 'يرجى رفع ملف بصيغة CSV فقط.');
            redirect('users/project_view/' . $project_id);
        }

        $handle = fopen($file_tmp, 'r');
        if (!$handle) {
            $this->session->set_flashdata('error', 'تعذر قراءة الملف.');
            redirect('users/project_view/' . $project_id);
        }

        // تخطي الهيدر
        fgetcsv($handle);

        $rowCount = 0;

        while (($row = fgetcsv($handle)) !== FALSE) {
            if (empty(array_filter($row))) continue;

            $identity = $row[0];    // رقم الهوية
            $new_value = $row[1];   // القيمة الجديدة

            // تحديث العمود بناءً على الهوية
            $this->db->where('n3', $identity);
            $this->db->update($table, [
                $column_name => $new_value
            ]);

            $rowCount++;
        }

        fclose($handle);
        $this->session->set_flashdata('success', "تم تعديل $rowCount صف بنجاح.");
    } else {
        $this->session->set_flashdata('error', 'يرجى اختيار ملف للرفع.');
    }

    redirect('users/upload_files_list/' . $project_id);
}




/**
 * دالة فرعية لتحديث البيانات على دفعات
 */
private function _process_batch_update($table, $column_name, $batchData)
{
    foreach ($batchData as $data) {
        $this->db->where('n1', $data['identity']);
        $this->db->update($table, [
            $column_name => $data['new_value']
        ]);
    }
}


 





