   public function sub_note()
{
    if (!$this->session->userdata('logged_in')) {
        redirect('login');
        return;
    }

    $data['id'] = $this->uri->segment(3, 0);
      $id = $data['id'];

    $this->form_validation->set_rules('note', 'محتوى الملاحظة', 'required');

    if ($this->form_validation->run() === FALSE) {
        $this->load->view('templateo/sub_note', $data);
    } else {
        $this->user_model->add_sub_note($id);

        // ✅ View يحتوي سكربت إغلاق النافذة
        echo "<script>
            alert('تم حفظ الملاحظة بنجاح');
            window.close(); // يغلق النافذة المنبثقة
        </script>";
    }
}



      

