     public function save_token() {
        $json = file_get_contents('php://input');
        $data = json_decode($json);
        $token = $data->token ?? null;

        if ($token) {
            $this->db->insert('fcm_tokens', ['token' => $token]);
            echo json_encode(['status' => 'success']);
        } else {
            echo json_encode(['status' => 'error']);
        }
    }

    public function send_notification() {
        $tokens = $this->db->get('fcm_tokens')->result_array();
        foreach ($tokens as $row) {
            $this->send_fcm_notification($row['token'], 'مرحبا 👋', 'هذا إشعار تجريبي 🎯');
        }
        echo "تم الإرسال.";
    }

    private function send_fcm_notification($token, $title, $body) {
        $url = 'https://fcm.googleapis.com/fcm/send';
        $serverKey = '🔒 YOUR_SERVER_KEY'; // لم يتم تفعيله لديك بعد

        $data = [
            'to' => $token,
            'notification' => [
                'title' => $title,
                'body' => $body,
                'icon' => 'icon.png',
                'click_action' => 'https://your-site.com'
            ]
        ];

        $headers = [
            'Authorization: key=' . $serverKey,
            'Content-Type: application/json'
        ];

        $ch = curl_init($url);
        curl_setopt($ch, CURLOPT_POSTFIELDS, json_encode($data));
        curl_setopt($ch, CURLOPT_HTTPHEADER, $headers);
        curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
        curl_exec($ch);
        curl_close($ch);
    }



