public function reimbursements_report() {

   $projects = $this->db->select('project_id, MAX(project) AS project_name')
    ->from('employee_reimbursements')
    ->where('status', 1)
    ->where("project != '' AND project NOT REGEXP '^[0-9]+$'")
    ->group_by('project_id')
    ->order_by('project_name', 'ASC')
    ->get()
    ->result_array();

$data['projects'] = $projects;





    $this->load->model('user_model');

    $data['report'] = [];
    $data['from_date'] = '';
    $data['to_date'] = '';


    if ($this->input->server('REQUEST_METHOD') == 'POST') {
        $from_date = $this->input->post('from_date'); // بصيغة yyyy/mm/dd
        $to_date = $this->input->post('to_date');     // بصيغة yyyy/mm/dd

        $data['from_date'] = $from_date;
        $data['to_date'] = $to_date;
      $selected_project_id = $this->input->post('project_name'); // ← القيمة ستكون project_id
$data['selected_project_id'] = $selected_project_id;



   $data['report'] = $this->user_model->get_reimbursements_with_targets($from_date, $to_date, $selected_project_id);
$data['selected_project_id'] = $selected_project_id;
$month_year = date('Y/m', strtotime($from_date));
$data['supervisor_projects'] = $this->user_model->get_supervisor_performance_fast($month_year);

$data['employee_performance'] = $this->user_model->get_employee_performance_fast($from_date, $to_date);




 


    }

    $this->load->view('templateo/reimbursements_report', $data);
}

