          public function get_user_sum_ajax()
{
    // التحقق من استقبال $userid
    $userid = $this->input->post('userid');
    if (!$userid) {
        echo json_encode(['status' => 'error', 'message' => 'User ID is required']);
        return;
    }

    // استدعاء الدالة من الموديل
    $total = $this->user_model->cuntt5524999k5214($userid);

    // إرسال النتيجة كاستجابة JSON
    echo json_encode(['status' => 'success', 'total' => $total]);
}






