       // controller: ReportController.php
public function get_realtime_report_data()
{
    // جلب بيانات الأداء من الموديل
    $data = $this->user_model->get_top_and_bottom_achievers1();

    // السدادات خلال آخر 5 دقائق
    $five_minutes_ago = date('Y/m/d H:i:s', strtotime('-1 minutes'));

    $this->db->select('
        e.id,
        e.n6 AS employee_id,
        u.name AS employee_name,
        e.n2 AS amount,
        e.n8 AS payment_date,
        e.project AS project_name
    ');
    $this->db->from('employee_reimbursements e');
    $this->db->join('users u', 'u.id = e.n6', 'left');
    $this->db->where('e.status', 1);
    $this->db->where('e.n8 >=', $five_minutes_ago);
    $this->db->order_by('e.n8', 'DESC');

    $query = $this->db->get();
    $data['recent_payments'] = $query->result();

    header('Content-Type: application/json; charset=utf-8');
    echo json_encode($data, JSON_UNESCAPED_UNICODE);
}






