       public function get_quality_by_mobile($mobile = null, $api_key = null) {
        if ($api_key !== $this->API_KEY) {
            echo json_encode([
                'status' => false,
                'message' => 'API Key غير صالح'
            ], JSON_UNESCAPED_UNICODE);
            return;
        }

        if (!$mobile || !preg_match('/^9665\d{8}$/', $mobile)) {
            echo json_encode([
                'status' => false,
                'message' => 'صيغة رقم الجوال غير صحيحة'
            ], JSON_UNESCAPED_UNICODE);
            return;
        }

        $query = $this->db->get_where('quality', ['mobile' => $mobile]);

        if ($query->num_rows() > 0) {
            echo json_encode([
                'status' => true,
                'data' => $query->row_array()
            ], JSON_UNESCAPED_UNICODE);
        } else {
            echo json_encode([
                'status' => false,
                'message' => 'لا توجد بيانات لهذا الرقم'
            ], JSON_UNESCAPED_UNICODE);
        }
    }

