    public function ceo_report()
{
    // لازم يكون مسجّل دخول
    if (!$this->session->userdata('logged_in')) {
        redirect('users/login');
        return;
    }

    // السماح فقط لهؤلاء المستخدمين
    $allowed_usernames = ['1001', '1835', '1146', '1140'];
    $username = (string) $this->session->userdata('username'); // غيّر المفتاح إذا كان مختلفاً عندك

    if (!in_array($username, $allowed_usernames, true)) {
        // إمّا رجّعه للرئيسية أو أعرض 404 — اختَر الأنسب لك
        // show_404();
        redirect('users/login');
        return;
    }

    // أي حواجز/صلاحيات إضافية عندك
    if ($this->session->userdata('type') == 10) {
        redirect('users/login');
        return;
    }

    // التحقق من حالة المستخدم كما كان سابقاً
    $user = $this->user_model->get_users101();
    $status3 = isset($user['status3']) ? $user['status3'] : null;
    if ($status3 !== '2') {
        redirect('users/re_pass');
        return;
    }

    // عرض الصفحة
    $this->load->view('templateo/ceo_report');
}

