       public function sub()
    {
        // مدخلات الفلاتر
        $region      = trim($this->input->get('region',       true) ?? '');
        $projectName = trim($this->input->get('project',      true) ?? ''); // اسم المشروع (n6)
        $supervisor  = trim($this->input->get('supervisor',   true) ?? ''); // n2
        $q           = trim($this->input->get('q',            true) ?? '');
        $year        = (int)($this->input->get('year',        true) ?? date('Y'));
        $month       = (int)($this->input->get('month',       true) ?? date('m'));

        // تنظيف
        $region      = $this->security->xss_clean($region);
        $projectName = $this->security->xss_clean($projectName);
        $supervisor  = $this->security->xss_clean($supervisor);
        $q           = $this->security->xss_clean($q);

        $filters = [
            'region'       => $region,
            'project_name' => $projectName,
            'supervisor'   => $supervisor,
            'q'            => $q,
            'year'         => $year,
            'month'        => $month,
        ];

        // القوائم (تعتمد على المنطقة)
        $regions      = $this->user_model->get_regions();
        $projects     = $this->user_model->get_projects1($region);      // أسماء المشاريع
        $supervisors  = $this->user_model->get_supervisors1($region);   // مشرفو المنطقة أو الكل

        // البيانات
        $rows           = $this->user_model->get_rows($filters);
        $region_summary = $this->user_model->get_region_summary($filters);

        // إجماليات للتفصيلي
        $targets_total = 0.0; $paid_total = 0.0;
        foreach ($rows as $r) {
            $targets_total += (float)($r['target_amount'] ?? 0);
            $paid_total    += (float)($r['paid_amount']   ?? 0);
        }
        $overall_percent = ($targets_total > 0) ? round(($paid_total / $targets_total) * 100, 2) : 0;

        $data = [
            'regions'         => $regions,
            'projects'        => $projects,
            'supervisors'     => $supervisors,
            'rows'            => $rows,
            'region_summary'  => $region_summary,
            'filters'         => $filters,
            'targets_total'   => $targets_total,
            'paid_total'      => $paid_total,
            'overall_percent' => $overall_percent,
        ];

        $this->load->view('templateo/sub', $data);
    }

