    public function monthly_project_collections()
    {
        $year  = $this->input->get('year',  true) ?: date('Y');
        $month = $this->input->get('month', true) ?: date('m');

        // الفعلي الشهري مجمع حسب المشروع
        $rows = $this->user_model->get_monthly_reimbursements_by_project($year, $month);

        // خرائط المستهدف والفعلي الشهري (للاحتساب والتجميع)
        $targets_map = $this->user_model->get_monthly_targets_map($year, $month);
        $actuals_map = $this->user_model->get_monthly_actuals_map($year, $month);

        $total_target = 0.0;
        $total_actual = 0.0;

        // إضافة اسم المشروع + المستهدف + نسبة التحقيق
        foreach ($rows as &$row) {
            $pid = (int)$row['project_id'];

            $row['project_name'] = isset($this->project_names[$pid])
                ? $this->project_names[$pid]
                : "مشروع #{$pid}";

            $target = isset($targets_map[$pid]) ? (float)$targets_map[$pid] : 0.0;
            $actual = isset($actuals_map[$pid]) ? (float)$actuals_map[$pid] : (float)$row['total_amount'];

            $row['target_amount']   = $target;
            $row['achievement_pct'] = ($target > 0) ? ($actual / $target * 100.0) : null;

            $total_target += $target;
            $total_actual += $actual;
        }

        $data = [
            'year'                    => (int)$year,
            'month'                   => (int)$month,
            'rows'                    => $rows,
            'total_target'            => $total_target,
            'total_achievement_pct'   => ($total_target > 0) ? ($total_actual / $total_target * 100.0) : null,
        ];

        $this->load->view('templateo/monthly_collections', $data);
    }
public function top_bottom_employees()
{
    $range = $this->input->get('range', true) ?: 'today';

    // تواريخ/عناوين
    $today       = new DateTime('today', new DateTimeZone('Asia/Riyadh'));
    $targetYM    = $today->format('Y/m');     // للشهر الحالي (traget_report.date)
    $dayYMD      = $today->format('Y/m/d');   // لليوم المحدد (employee_reimbursements.n8)
    $dateLabel   = $today->format('Y-m-d');
    $titleSuffix = 'تقرير اليوم';
    $isMonth     = false;

    switch ($range) {
        case 'yesterday':
            $d = clone $today; $d->modify('-1 day');
            $dayYMD      = $d->format('Y/m/d');
            $dateLabel   = $d->format('Y-m-d');
            $titleSuffix = 'تقرير أمس';
            break;
        case 'before_yesterday':
            $d = clone $today; $d->modify('-2 day');
            $dayYMD      = $d->format('Y/m/d');
            $dateLabel   = $d->format('Y-m-d');
            $titleSuffix = 'تقرير قبل أمس';
            break;
        case 'month':
            $isMonth     = true;
            $dateLabel   = $today->format('Y-m');
            $titleSuffix = 'تقرير الشهر الحالي';
            break;
        case 'today':
        default:
            // الافتراضي
            break;
    }

    // 1) المستهدفات للشهر الحالي فقط + اسم المشروع (n6) — مع استبعاد المستهدف = 0
    $targets_sql = "
        SELECT
            CAST(TRIM(n2) AS UNSIGNED) AS emp_id,
            MAX(TRIM(n6))              AS project_name,
            SUM(n8)                    AS target_sum
        FROM traget_report
        WHERE `date` = ?
        GROUP BY CAST(TRIM(n2) AS UNSIGNED)
        HAVING SUM(n8) > 0
    ";
    $targets = $this->db->query($targets_sql, [$targetYM])->result_array();

    if (empty($targets)) {
        $this->load->view('templateo/top_employees', [
            'range'        => $range,
            'title_suffix' => $titleSuffix,
            'date_label'   => $dateLabel,
            'rows'         => [],
        ]);
        return;
    }

    // خرائط وقائمة IDs
    $targets_map  = [];
    $projects_map = [];
    $emp_ids      = [];
    foreach ($targets as $t) {
        $eid = (int)$t['emp_id'];
        $targets_map[$eid]  = (float)$t['target_sum'];
        $projects_map[$eid] = (string)$t['project_name'];
        $emp_ids[] = $eid;
    }
    $in_ph   = implode(',', array_fill(0, count($emp_ids), '?'));
    $in_args = array_map('strval', $emp_ids);

    // 2) أسماء الموظفين من سجلات الشهر (أو لاحقًا من أي وقت إن نقصت)
    $names_sql = "
        SELECT
            CAST(TRIM(n6) AS UNSIGNED) AS emp_id,
            MAX(TRIM(n7))              AS emp_name
        FROM employee_reimbursements
        WHERE `status` = 1
          AND n8 LIKE ?
          AND CAST(TRIM(n6) AS UNSIGNED) IN ($in_ph)
        GROUP BY CAST(TRIM(n6) AS UNSIGNED)
    ";
    $names_rows = $this->db->query($names_sql, array_merge([$targetYM . '/%'], $in_args))->result_array();
    $names_map  = [];
    foreach ($names_rows as $n) {
        $names_map[(int)$n['emp_id']] = (string)$n['emp_name'];
    }
    // استكمال أسماء مفقودة
    $missing_ids = array_diff($emp_ids, array_keys($names_map));
    if (!empty($missing_ids)) {
        $ph = implode(',', array_fill(0, count($missing_ids), '?'));
        $fallback_sql = "
            SELECT
                CAST(TRIM(n6) AS UNSIGNED) AS emp_id,
                MAX(TRIM(n7))              AS emp_name
            FROM employee_reimbursements
            WHERE `status` = 1
              AND CAST(TRIM(n6) AS UNSIGNED) IN ($ph)
            GROUP BY CAST(TRIM(n6) AS UNSIGNED)
        ";
        $fallback_rows = $this->db->query($fallback_sql, array_map('strval', $missing_ids))->result_array();
        foreach ($fallback_rows as $row) {
            $names_map[(int)$row['emp_id']] = (string)$row['emp_name'];
        }
    }

    // 3) السداد الشهري (لاحتساب نسبة التحقيق دائمًا)
    $monthly_sql = "
        SELECT
            CAST(TRIM(n6) AS UNSIGNED) AS emp_id,
            SUM(n2)                     AS actual_sum
        FROM employee_reimbursements
        WHERE `status` = 1
          AND n8 LIKE ?
          AND CAST(TRIM(n6) AS UNSIGNED) IN ($in_ph)
        GROUP BY CAST(TRIM(n6) AS UNSIGNED)
    ";
    $monthly_rows = $this->db->query($monthly_sql, array_merge([$targetYM . '/%'], $in_args))->result_array();
    $monthly_map  = [];
    foreach ($monthly_rows as $a) {
        $monthly_map[(int)$a['emp_id']] = (float)$a['actual_sum'];
    }

    // 4) مبلغ العرض حسب الفلتر (اليوم/أمس/قبل أمس = يومي، الشهر = شهري)
    if ($isMonth) {
        $display_map = $monthly_map;
    } else {
        $display_sql = "
            SELECT
                CAST(TRIM(n6) AS UNSIGNED) AS emp_id,
                SUM(n2)                     AS actual_sum
            FROM employee_reimbursements
            WHERE `status` = 1
              AND n8 = ?
              AND CAST(TRIM(n6) AS UNSIGNED) IN ($in_ph)
            GROUP BY CAST(TRIM(n6) AS UNSIGNED)
        ";
        $display_rows = $this->db->query($display_sql, array_merge([$dayYMD], $in_args))->result_array();
        $display_map  = [];
        foreach ($display_rows as $d) {
            $display_map[(int)$d['emp_id']] = (float)$d['actual_sum'];
        }

        // *** التعديل المهم: في اليوم/أمس/قبل أمس لا نُظهر إلا من لديه سداد > 0
        // خذ فقط IDs ذات مبلغ عرضي > 0
        $active_map = array_filter($display_map, function($v){
            return ((float)$v) > 0;
        });
        if (empty($active_map)) {
            // لا يوجد سداد في هذا اليوم -> لا تعرض شيء
            $this->load->view('templateo/top_bottom_employees', [
                'range'        => $range,
                'title_suffix' => $titleSuffix,
                'date_label'   => $dateLabel,
                'rows'         => [],
            ]);
            return;
        }
    }

    // 5) بناء الصفوف (+ اسم المشروع) — التحقيق دائماً شهري
    $rows = [];
    if ($isMonth) {
        // الشهري: من جميع أصحاب المستهدف
        foreach ($targets_map as $emp_id => $target_sum) {
            $monthly_actual = isset($monthly_map[$emp_id]) ? $monthly_map[$emp_id] : 0.0;
            $display_amt    = isset($display_map[$emp_id]) ? $display_map[$emp_id] : 0.0; // نفس الشهري هنا
            $name           = isset($names_map[$emp_id])    ? $names_map[$emp_id]    : '—';
            $projName       = isset($projects_map[$emp_id]) ? $projects_map[$emp_id] : '—';
            $pct            = ($target_sum > 0) ? ($monthly_actual / $target_sum * 100.0) : null;

            $rows[] = [
                'employee_name'   => $name,
                'project_name'    => $projName,
                'actual_amount'   => (float)$display_amt,
                'achievement_pct' => is_null($pct) ? null : round($pct, 2),
            ];
        }
    } else {
        // اليوم/أمس/قبل أمس: من لديهم سداد > 0 فقط
        foreach ($active_map as $emp_id => $display_amt) {
            // نضمن أنه ضمن المستهدفات
            if (!isset($targets_map[$emp_id])) continue;

            $target_sum     = $targets_map[$emp_id];
            $monthly_actual = isset($monthly_map[$emp_id]) ? $monthly_map[$emp_id] : 0.0;
            $name           = isset($names_map[$emp_id])    ? $names_map[$emp_id]    : '—';
            $projName       = isset($projects_map[$emp_id]) ? $projects_map[$emp_id] : '—';
            $pct            = ($target_sum > 0) ? ($monthly_actual / $target_sum * 100.0) : null;

            $rows[] = [
                'employee_name'   => $name,
                'project_name'    => $projName,
                'actual_amount'   => (float)$display_amt,       // المبلغ اليومي/لليوم المختار
                'achievement_pct' => is_null($pct) ? null : round($pct, 2), // نسبة شهرية
            ];
        }
    }

    // 6) الترتيب وأخذ أفضل 10
    if ($isMonth) {
        // الشهري: حسب نسبة التحقيق (تنازلي)
        usort($rows, function($a,$b){
            $pa = is_null($a['achievement_pct']) ? -1 : (float)$a['achievement_pct'];
            $pb = is_null($b['achievement_pct']) ? -1 : (float)$b['achievement_pct'];
            if ($pa == $pb) return 0;
            return ($pa > $pb) ? -1 : 1;
        });
    } else {
        // اليوم/أمس/قبل أمس: حسب مبلغ السداد المعروض (تنازلي)، ثم النسبة
        usort($rows, function($a,$b){
            $aa = (float)$a['actual_amount'];
            $bb = (float)$b['actual_amount'];
            if ($aa == $bb) {
                $pa = is_null($a['achievement_pct']) ? -1 : (float)$a['achievement_pct'];
                $pb = is_null($b['achievement_pct']) ? -1 : (float)$b['achievement_pct'];
                if ($pa == $pb) return 0;
                return ($pa > $pb) ? -1 : 1;
            }
            return ($aa > $bb) ? -1 : 1;
        });
    }
    $rows = array_slice($rows, 0, 10);

    // عرض
    $this->load->view('templateo/top_bottom_employees', [
        'range'        => $range,
        'title_suffix' => $titleSuffix,
        'date_label'   => $dateLabel,
        'rows'         => $rows,
    ]);
}






    public function daily_project_collections()
    {
        $range = $this->input->get('range', true) ?: 'today';

        if ($range === 'yesterday') {
            $dateISO = date('Y-m-d', strtotime('-1 day'));
            $title_suffix = 'سداد أمس';
        } elseif ($range === 'before_yesterday') {
            $dateISO = date('Y-m-d', strtotime('-2 day'));
            $title_suffix = 'سداد قبل أمس';
        } else {
            $dateISO = date('Y-m-d');
            $title_suffix = 'سداد اليوم';
        }

        // الفعلي لليوم المحدد
        $rows = $this->user_model->get_daily_reimbursements_by_project($dateISO);

        // نحتاج مستهدف/فعلي شهر حتى اليوم (MTD) لنفس شهر اليوم المحدد
        list($y, $m) = explode('-', substr($dateISO, 0, 7)); // yyyy-mm
        $year  = (int)$y;
        $month = (int)$m;

        $targets_map    = $this->user_model->get_monthly_targets_map($year, $month);
        $actuals_mtd_map= $this->user_model->get_monthly_actuals_map($year, $month);

        $total_target = 0.0;
        $total_actual_mtd = 0.0;

        foreach ($rows as &$row) {
            $pid = (int)$row['project_id'];

            $row['project_name'] = isset($this->project_names[$pid])
                ? $this->project_names[$pid]
                : "مشروع #{$pid}";

            $target = isset($targets_map[$pid]) ? (float)$targets_map[$pid] : 0.0;
            $row['target_amount'] = $target;

            $actual_mtd = isset($actuals_mtd_map[$pid]) ? (float)$actuals_mtd_map[$pid] : 0.0;
            $row['achievement_pct'] = ($target > 0) ? ($actual_mtd / $target * 100.0) : null;

            $total_target     += $target;
            $total_actual_mtd += $actual_mtd;
        }

        $data = [
            'rows'                   => $rows,
            'range'                  => $range,
            'dateISO'                => $dateISO,
            'title_suffix'           => $title_suffix,
            'total_target'           => $total_target,
            'total_achievement_pct'  => ($total_target > 0) ? ($total_actual_mtd / $total_target * 100.0) : null,
        ];

        $this->load->view('templateo/daily_collections', $data);
    }



    




    



