public function suggestions() 
{ 
    // تحقق من تسجيل الدخول
    if (!$this->session->userdata('logged_in')) {
        redirect('users/login');
        return;
    }

    // تحميل بيانات العملاء حسب نوع المستخدم
    $user_type = $this->session->userdata('type');

if ($user_type == 2) {
    $data['customers'] = $this->user_model->get_suggestions();
} elseif (
    $user_type == 3 &&
    ($this->session->userdata('username') == "1835" || $this->session->userdata('username') == "1140")
) {
    $data['customers'] = $this->user_model->get_suggestions101();
} elseif ($user_type == 3) {
    $data['customers'] = $this->user_model->get_suggestions();
} elseif ($user_type == 1) {
    $data['customers'] = $this->user_model->get_suggestions();
} else {
    $data['customers'] = $this->user_model->get_suggestions();
}


    // عرض الواجهات
    $this->load->view('templateo/header2');  
    $this->load->view('templateo/suggestions', $data);
    $this->load->view('templateo/footer2');
}




