       function can_submit_new_request($contract_id) {
    $project = $this->session->userdata('project');
    $orders_table = '';

    switch ($project) {
        case 1:  $orders_table = 'order_emkan';   break;
        case 2:  $orders_table = 'order_alahli';  break;
        case 3:  // fall-through
        case 14: $orders_table = 'order_alrajhi'; break;
        case 4:  $orders_table = 'order_alenma';  break;
        case 5:  $orders_table = 'order_alriyad'; break;
        default: return 0; // لا يُسمح افتراضيًا إذا لم يكن المشروع معروفًا
    }

    // التحقق: هل هناك أي طلب حالته ≠ 5 أو 7؟
    $sql = "
        SELECT COUNT(*) AS invalid_count
        FROM $orders_table
        WHERE n8 = ? AND status NOT IN (10, 7)
    ";

    $query = $this->db->query($sql, [$contract_id]);
    $result = $query->row();

    // إذا لا يوجد أي طلب غير مسموح → يُسمح برفع طلب جديد
    return ($result->invalid_count == 0) ? 1 : 0;
}




