    public function check_username_exists()
{
    $username = $this->input->post('username');

    $exists = $this->db
                  ->where('username', $username)
                  ->get('users')
                  ->num_rows() > 0;

    echo $exists ? 'exists' : 'available';
}

public function check_email_exists()
{
    $email = $this->input->post('email');

    $exists = $this->db
                  ->where('email', $email)
                  ->get('users')
                  ->num_rows() > 0;

    echo $exists ? 'exists' : 'available';
}








